import{_ as t,o as r,c as a,a2 as s}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"数据、可观测性与验证","description":"","frontmatter":{},"headers":[],"relativePath":"product/data-observability.md","filePath":"product/data-observability.md","lastUpdated":1780482865000}'),o={name:"product/data-observability.md"};function c(d,e,i,n,l,h){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="数据、可观测性与验证" tabindex="-1">数据、可观测性与验证 <a class="header-anchor" href="#数据、可观测性与验证" aria-label="Permalink to &quot;数据、可观测性与验证&quot;">​</a></h1><h2 id="本地数据" tabindex="-1">本地数据 <a class="header-anchor" href="#本地数据" aria-label="Permalink to &quot;本地数据&quot;">​</a></h2><p>默认数据目录是 <code>~/.codex-to-im</code>。</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>代码入口</th></tr></thead><tbody><tr><td><code>config.v2.json</code></td><td>结构化 runtime 和通道配置</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/configuration/index.ts" target="_blank" rel="noreferrer">src/configuration/index.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/schemas/config.v2.schema.json" target="_blank" rel="noreferrer">schemas/config.v2.schema.json</a></td></tr><tr><td><code>config.env</code></td><td>兼容旧工具和 bootstrap 的 env 快照</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/configuration/index.ts" target="_blank" rel="noreferrer">src/configuration/index.ts</a></td></tr><tr><td><code>data/sessions.json</code></td><td>BridgeSession</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/schemas/data/sessions.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/sessions.v1.schema.json</a></td></tr><tr><td><code>data/channel-chats.json</code></td><td>ChannelChat 绑定</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/schemas/data/channel-chats.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/channel-chats.v1.schema.json</a></td></tr><tr><td><code>data/messages/&lt;sessionId&gt;.json</code></td><td>Bridge 消息缓存</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/schemas/data/messages.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/messages.v1.schema.json</a></td></tr><tr><td><code>data/audit.json</code></td><td>审计日志</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/schemas/data/audit.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/audit.v1.schema.json</a></td></tr><tr><td><code>runtime/status.json</code></td><td>Bridge 运行状态</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/entrypoints/daemon.ts" target="_blank" rel="noreferrer">src/entrypoints/daemon.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/local-service/manager.ts" target="_blank" rel="noreferrer">src/local-service/manager.ts</a></td></tr><tr><td><code>runtime/ui-server.json</code></td><td>UI 运行状态</td><td><a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/server.ts" target="_blank" rel="noreferrer">src/operator-ui/server.ts</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/local-service/manager.ts" target="_blank" rel="noreferrer">src/local-service/manager.ts</a></td></tr></tbody></table><p>Codex 自有数据仍在 <code>~/.codex</code>；Codex-to-IM 只读索引和镜像。Claude Code 自有 JSONL 也由 Claude Code 生成；bridge 只保存可继续定位它的 runtime 身份。</p><h2 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h2><p>Codex-to-IM 的可观测性来自四层：</p><ul><li>IM 内状态命令：<code>/status</code>、<code>/check</code>、<code>/his</code>、<code>/doctor</code>。</li><li>本地日志：<code>~/.codex-to-im/logs/bridge.log</code>、hot update log。</li><li>本地 JSON 数据：sessions、channel-chats、messages、audit。</li><li>真实 E2E 报告：real Feishu harness 输出的成功或失败 JSON report。</li></ul><p>设计模块：</p><ul><li>状态命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/status.ts" target="_blank" rel="noreferrer">src/bridge/command/status.ts</a></li><li>诊断命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/diagnostics.ts" target="_blank" rel="noreferrer">src/bridge/command/diagnostics.ts</a></li><li>健康检查：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/health/runtime.ts" target="_blank" rel="noreferrer">src/bridge/health/runtime.ts</a></li><li>transcript source：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/session/transcript-source.ts" target="_blank" rel="noreferrer">src/bridge/session/transcript-source.ts</a></li><li>Doctor 脚本：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/scripts/doctor.sh" target="_blank" rel="noreferrer">scripts/doctor.sh</a>、<a href="https://github.com/zhangle1987/codex-to-im/blob/master/scripts/doctor.ps1" target="_blank" rel="noreferrer">scripts/doctor.ps1</a></li></ul><h2 id="验证入口" tabindex="-1">验证入口 <a class="header-anchor" href="#验证入口" aria-label="Permalink to &quot;验证入口&quot;">​</a></h2><ul><li>普通单元/集成测试：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/scripts/run-tests.js" target="_blank" rel="noreferrer">scripts/run-tests.js</a></li><li>类型检查：<code>npm run typecheck</code></li><li>真实飞书 E2E harness：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/scripts/real-feishu-e2e.ts" target="_blank" rel="noreferrer">scripts/real-feishu-e2e.ts</a></li><li>覆盖审计文档：<a href="./../testing/coverage-audit">docs/testing/coverage-audit.md</a></li><li>真实飞书 E2E：<a href="./../testing/real-feishu/">docs/testing/real-feishu/index.md</a></li></ul><p>真实飞书 E2E 的目标不是替代所有单元测试，而是证明关键用户场景确实能经过飞书客户端、真实 bridge、真实 runtime provider 和真实回复链路。</p>',13)])])}const g=t(o,[["render",c]]);export{b as __pageData,g as default};
